class Solution:
    def maxPartitionsAfterOperations(self, s: str, k: int) -> int:
        def count_partitions(s, k):
            partitions = 0
            freq = {}
            for ch in s:
                if ch in freq:
                    freq[ch] += 1
                else:
                    freq[ch] = 1
                if len(freq) > k:
                    partitions += 1
                    freq = {ch: 1}
            partitions += 1  # for the last partition
            return partitions

        max_partitions = 0
        n = len(s)
        for i in range(n):
            for c in 'abcdefghijklmnopqrstuvwxyz':
                if c == s[i]:
                    continue
                new_s = s[:i] + c + s[i+1:]
                max_partitions = max(max_partitions, count_partitions(new_s, k))
        return max_partitions
